1→import React, { useState, useEffect } from 'react';
2→import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
3→import Login from './components/Login';
4→import Dashboard from './components/Dashboard';
5→import AdminPanel from './components/AdminPanel';
6→import MasterPanel from './components/MasterPanel';
7→import NazoratchiPanel from './components/NazoratchiPanel';
8→import UsersPanel from './components/UsersPanel';
9→import ReportsPanel from './components/ReportsPanel';
10→import MechanicPanel from './components/MechanicPanel';
11→import Sidebar from './components/Sidebar';
12→
13→function App() {
14→  const [user, setUser] = useState(JSON.parse(localStorage.getItem('user')) || null);
15→  const [activeTab, setActiveTab] = useState('run');
16→
17→  const handleLogin = (userData) => {
18→    localStorage.setItem('user', JSON.stringify(userData));
19→    setUser(userData);
20→  };
21→
22→  const handleLogout = () => {
23→    localStorage.removeItem('user');
24→    localStorage.removeItem('token');
25→    setUser(null);
26→    setActiveTab('run');
27→  };
28→
29→  const renderContent = () => {
30→    switch (activeTab) {
31→      case 'run':
32→        return <Dashboard user={user} />;
33→      case 'report':
34→        return <ReportsPanel user={user} />;
35→      case 'mechanic':
36→        return <MechanicPanel user={user} />;
37→      case 'admin':
38→        return <AdminPanel user={user} />;
39→      case 'master':
40→        return <MasterPanel user={user} />;
41→      case 'nazoratchi':
42→        return <NazoratchiPanel user={user} />;
43→      case 'users':
44→        return <UsersPanel user={user} />;
45→      default:
46→        return <Dashboard user={user} />;
47→    }
48→  };
49→
50→  return (
51→    <Router>
52→      <Routes>
53→        <Route path="/login" element={!user ? <Login onLogin={handleLogin} /> : <Navigate to="/" />} />
54→        <Route path="/*" element={
55→          user ? (
56→            <div className="app-container">
57→              <Sidebar user={user} activeTab={activeTab} onTabChange={setActiveTab} onLogout={handleLogout} />
58→              <div className="main-content">
59→                {renderContent()}
60→              </div>
61→            </div>
62→          ) : (
63→            <Navigate to="/login" />
64→          )
65→        } />
66→      </Routes>
67→    </Router>
68→  );
69→}
70→
71→export default App;
EOF

